package com.example.sprintsight.security;

import com.example.sprintsight.dtos.responses.ApiError;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.jspecify.annotations.NonNull;
import org.springframework.http.MediaType;
import org.springframework.security.core.AuthenticationException;
import org.springframework.security.web.AuthenticationEntryPoint;
import org.springframework.stereotype.Component;
import tools.jackson.databind.ObjectMapper;

import java.io.IOException;

@Slf4j
@Component
@RequiredArgsConstructor
public class JwtAuthenticationEntryPoint implements AuthenticationEntryPoint {
    private final ObjectMapper objectMapper;

    @Override
    public void commence(HttpServletRequest request, HttpServletResponse response, @NonNull AuthenticationException ex)
            throws IOException {
        log.warn("Unauthorized access attempt: {}", request.getRequestURI());

        response.setContentType(MediaType.APPLICATION_JSON_VALUE);
        response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);

        ApiError body = new ApiError("Unauthorized");
        objectMapper.writeValue(response.getOutputStream(), body);
    }
}

package com.example.sprintsight.security;

import com.example.sprintsight.services.CustomUserDetailsService;
import io.jsonwebtoken.ExpiredJwtException;
import io.jsonwebtoken.JwtException;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.jspecify.annotations.NonNull;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.web.authentication.WebAuthenticationDetailsSource;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;

@Slf4j
@Component
@RequiredArgsConstructor
public class JwtFilter extends OncePerRequestFilter {
    private final JwtService jwtService;
    private final CustomUserDetailsService userDetailsService;

    @Override
    protected void doFilterInternal(
            @NonNull HttpServletRequest request,
            @NonNull HttpServletResponse response,
            @NonNull FilterChain filterChain
    ) throws ServletException, IOException {
        String jwt = jwtService.getJwtFromCookies(request);

        if (jwt == null) {
            filterChain.doFilter(request, response);

            return;
        }

        try {
            String username = jwtService.extractUsername(jwt);

            if (username != null && SecurityContextHolder.getContext().getAuthentication() == null) {
                UserDetails userDetails = userDetailsService.loadUserByUsername(username);

                if (jwtService.validateJwtToken(jwt, userDetails)) {
                    UsernamePasswordAuthenticationToken authentication =
                            new UsernamePasswordAuthenticationToken(
                                    userDetails, null, userDetails.getAuthorities());

                    authentication.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));

                    SecurityContextHolder.getContext().setAuthentication(authentication);
                }
            }
        } catch (ExpiredJwtException e) {
            log.warn("Expired JWT token for request {}: {}", request.getRequestURI(), e.getMessage());
        } catch (JwtException e) {
            log.warn("Invalid JWT token for request {}: {}", request.getRequestURI(), e.getMessage());
        }

        filterChain.doFilter(request, response);
    }
}

package com.example.sprintsight.security;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.security.Keys;
import jakarta.servlet.http.Cookie;
import jakarta.servlet.http.HttpServletRequest;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.ResponseCookie;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Service;
import org.springframework.web.util.WebUtils;

import javax.crypto.SecretKey;
import java.util.Base64;
import java.util.Date;
import java.util.function.Function;

@Slf4j
@Service
public class JwtService {
    @Value("${SprintSight.app.jwtSecret}")
    private String jwtSecret;

    private static final String jwtCookie = "SprintSightJwtCookie";
    private static final String jwtRefreshCookie = "SprintSightJwtRefreshCookie";

    private final long jwtExpiration = 15 * 60 * 1000;

    public ResponseCookie generateJwtCookie(UserDetails userDetails) {
        String jwt = generateJwtToken(userDetails.getUsername());

        return generateCookie(jwtCookie, jwt, "/api", jwtExpiration / 1000);
    }

    public ResponseCookie generateRefreshJwtCookie(String refreshToken) {
        return generateCookie(jwtRefreshCookie, refreshToken, "/api/auth/refresh", 7 * 24 * 60 * 60);
    }

    public String getJwtFromCookies(HttpServletRequest request) {
        return getCookieValueByName(request, jwtCookie);
    }

    public String getJwtRefreshFromCookies(HttpServletRequest request) {
        return getCookieValueByName(request, jwtRefreshCookie);
    }

    public ResponseCookie getCleanJwtCookie() {
        return generateCookie(jwtCookie, null, "/api", 0);
    }

    public ResponseCookie getCleanJwtRefreshCookie() {
        return generateCookie(jwtRefreshCookie, null, "/api/auth/refresh", 0);
    }

    public String extractUsername(String token) {
        return extractClaim(token, Claims::getSubject);
    }

    public boolean validateJwtToken(String token, UserDetails userDetails) {
        final String username = extractUsername(token);

        return username.equals(userDetails.getUsername()) && !isTokenExpired(token);
    }

    private boolean isTokenExpired(String token) {
        return extractClaim(token, Claims::getExpiration).before(new Date());
    }

    private  String generateJwtToken(String username) {
        return Jwts.builder()
                .subject(username)
                .issuedAt(new Date())
                .expiration(new Date(System.currentTimeMillis() + jwtExpiration))
                .signWith(getKey())
                .compact();
    }

    private SecretKey getKey() {
        return Keys.hmacShaKeyFor(Base64.getUrlDecoder().decode(jwtSecret));
    }

    private ResponseCookie generateCookie(String name, String value, String path, long maxAge) {
        return ResponseCookie.from(name, value)
                .path(path)
                .maxAge(maxAge)
                .httpOnly(true)
                .secure(true)
                .sameSite("None")
                .build();
    }

    private <T> T extractClaim(String token, Function<Claims, T> claimResolver) {
        return claimResolver.apply(extractAllClaims(token));
    }

    private Claims extractAllClaims(String token) {
        return Jwts.parser()
                .verifyWith(getKey())
                .build()
                .parseSignedClaims(token)
                .getPayload();
    }

    private String getCookieValueByName(HttpServletRequest request, String name) {
        Cookie cookie = WebUtils.getCookie(request, name);

        return cookie != null ? cookie.getValue() : null;
    }
}

package com.example.sprintsight.security;

import com.example.sprintsight.entities.UserRole;
import com.example.sprintsight.entities.User;
import lombok.Getter;
import lombok.NonNull;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.UserDetails;

import java.io.Serial;
import java.io.Serializable;
import java.util.Collection;
import java.util.List;
import java.util.UUID;

@Slf4j
public class UserPrincipal implements UserDetails, Serializable {
    @Serial
    private static final long serialVersionUID = 1L;

    @Getter
    private final UUID id;
    private final String username;
    private final String password;
    private final UserRole userRole;
    private final boolean enabled;

    private UserPrincipal(UUID id, String username, String password, UserRole userRole, boolean enabled) {
        this.id = id;
        this.username = username;
        this.password = password;
        this.userRole = userRole;
        this.enabled = enabled;
    }

    public static UserPrincipal from(User user) {
        return new UserPrincipal(
                user.getId(),
                user.getUsername(),
                user.getPassword(),
                user.getUserRole(),
                user.isEnabled()
        );
    }

    @Override
    @NonNull
    public Collection<? extends GrantedAuthority> getAuthorities() {
        return List.of(new SimpleGrantedAuthority("ROLE_" + userRole.name()));
    }

    @Override
    public String getPassword() { return password; }

    @Override
    @NonNull
    public String getUsername() { return username; }

    @Override
    public boolean isEnabled() { return enabled; }

    @Override
    public boolean isAccountNonExpired() { return true; }

    @Override
    public boolean isAccountNonLocked() { return true; }

    @Override
    public boolean isCredentialsNonExpired() { return true; }
}

package com.example.sprintsight.services;

import com.example.sprintsight.dtos.requests.CommentRequest;
import com.example.sprintsight.dtos.responses.CommentResponse;
import com.example.sprintsight.entities.*;
import com.example.sprintsight.mappers.CommentMapper;
import com.example.sprintsight.repositories.CommentRepository;
import jakarta.persistence.EntityNotFoundException;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;

@Slf4j
@Service
@RequiredArgsConstructor
public class CommentService {
    private final CommentRepository commentRepository;
    private final IssueService issueService;
    private final UserService userService;
    private final ProjectAuthorizationService authorizationService;
    private final CommentMapper commentMapper;

    @Transactional(readOnly = true)
    public List<CommentResponse> getComments(UUID issueId, UUID principalId) {
        Issue issue = issueService.findIssue(issueId);

        authorizationService.getMemberOrThrow(principalId, issue.getProject().getId());

        return commentRepository.findByIssue_IdOrderByCreatedAtAsc(issueId)
                .stream()
                .map(commentMapper::toCommentResponse)
                .toList();
    }

    @Transactional
    public CommentResponse addComment(CommentRequest request, UUID issueId, UUID principalId) {
        Issue issue = issueService.findIssue(issueId);

        authorizationService.requireAnyRole(principalId, issue.getProject().getId(), ProjectRole.PRODUCT_OWNER,
                ProjectRole.SCRUM_MASTER, ProjectRole.DEVELOPER);

        User author = userService.findUser(principalId);

        Comment comment = commentMapper.toEntity(request);
        comment.setIssue(issue);
        comment.setAuthor(author);

        Comment saved = commentRepository.save(comment);

        log.info("Comment {} added to issue {}", saved.getId(), issueId);

        return commentMapper.toCommentResponse(saved);
    }

    @Transactional
    public CommentResponse updateComment(CommentRequest request, UUID commentId, UUID principalId) {
        Comment comment = findComment(commentId);

        verifyCommentOwnership(comment, principalId);

        comment.setContent(request.content());
        Comment saved = commentRepository.save(comment);

        return commentMapper.toCommentResponse(saved);
    }

    @Transactional
    public void deleteComment(UUID commentId, UUID principalId) {
        Comment comment = findComment(commentId);

        verifyCommentOwnership(comment, principalId);

        commentRepository.delete(comment);

        log.info("Deleted comment {}", commentId);
    }

    private Comment findComment(UUID commentId) {
        return commentRepository.findById(commentId)
                .orElseThrow(() -> new EntityNotFoundException("Comment not found"));
    }

    private void verifyCommentOwnership(Comment comment, UUID principalId) {
        if (!comment.getAuthor().getId().equals(principalId)) {
            throw new AccessDeniedException("You can only modify your own comments");
        }
    }
}

