package com.example.sprintsight.services;

import com.example.sprintsight.dtos.requests.SendInvitationRequest;
import com.example.sprintsight.dtos.responses.InvitationResponse;
import com.example.sprintsight.entities.InvitationStatus;
import com.example.sprintsight.entities.Project;
import com.example.sprintsight.entities.ProjectInvitation;
import com.example.sprintsight.entities.User;
import com.example.sprintsight.mappers.InvitationMapper;
import com.example.sprintsight.repositories.ProjectInvitationRepository;
import com.example.sprintsight.repositories.ProjectMemberRepository;
import jakarta.persistence.EntityNotFoundException;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Instant;
import java.util.List;
import java.util.UUID;

@Slf4j
@Service
@RequiredArgsConstructor
public class InvitationService {
    private final UserService userService;
    private final ProjectService projectService;
    private final InvitationMapper invitationMapper;
    private final ProjectMemberService projectMemberService;
    private final ProjectMemberRepository projectMemberRepository;
    private final ProjectInvitationRepository invitationRepository;

    @Transactional(readOnly = true)
    public List<InvitationResponse> getPendingInvitations(UUID userId) {
        return invitationRepository
                .findByReceiver_IdAndStatus(userId, InvitationStatus.PENDING)
                .stream()
                .map(invitationMapper::toInvitationResponse)
                .toList();
    }

    @Transactional
    public InvitationResponse sendInvitation(
            SendInvitationRequest request,
            UUID projectId,
            UUID senderId
    ) {
        User sender = userService.findUser(senderId);
        User receiver = userService.findUser(request.receiverId());
        Project project = projectService.findProject(projectId);

        if (projectMemberRepository.existsById_UserIdAndId_ProjectId(request.receiverId(), projectId)) {
            throw new IllegalStateException("User is already a member of this project");
        }

        if (invitationRepository.existsByProject_IdAndReceiver_IdAndStatus(
                projectId, request.receiverId(), InvitationStatus.PENDING)) {
            throw new IllegalStateException("A pending invitation already exists for this user");
        }

        ProjectInvitation invitation = invitationMapper.toEntity(request);
        invitation.setProject(project);
        invitation.setSender(sender);
        invitation.setReceiver(receiver);

        ProjectInvitation saved = invitationRepository.save(invitation);
        InvitationResponse response = invitationMapper.toInvitationResponse(saved);

        log.info("Invitation sent from {} to {} for project {}", senderId, request.receiverId(), projectId);

        return response;
    }

    @Transactional
    public InvitationResponse acceptInvitation(UUID invitationId, UUID principalId) {
        ProjectInvitation invitation = findPendingInvitation(invitationId, principalId);

        invitation.setStatus(InvitationStatus.ACCEPTED);
        invitation.setRespondedAt(Instant.now());
        invitationRepository.save(invitation);

        projectMemberService.addProjectMember(
                principalId, invitation.getIntendedRole(), invitation.getProject().getId()
        );

        return invitationMapper.toInvitationResponse(invitation);
    }

    @Transactional
    public InvitationResponse rejectInvitation(UUID invitationId, UUID principalId) {
        ProjectInvitation invitation = findPendingInvitation(invitationId, principalId);

        invitation.setStatus(InvitationStatus.REJECTED);
        invitation.setRespondedAt(Instant.now());
        invitationRepository.save(invitation);

        return invitationMapper.toInvitationResponse(invitation);
    }

    private ProjectInvitation findPendingInvitation(UUID invitationId, UUID principalId) {
        ProjectInvitation invitation = invitationRepository.findById(invitationId)
                .orElseThrow(() -> new EntityNotFoundException("Invitation not found"));

        if (!invitation.getReceiver().getId().equals(principalId)) {
            throw new AccessDeniedException("You are not the recipient of this invitation");
        }

        if (invitation.getStatus() != InvitationStatus.PENDING) {
            throw new IllegalStateException("Invitation has already been responded to");
        }

        return invitation;
    }
}

package com.example.sprintsight.services;

import com.example.sprintsight.dtos.requests.IssuePriorityRequest;
import com.example.sprintsight.dtos.requests.IssueStatusRequest;
import com.example.sprintsight.dtos.requests.IssueTypeRequest;
import com.example.sprintsight.dtos.responses.IssuePriorityConfigurationResponse;
import com.example.sprintsight.dtos.responses.IssueStatusConfigurationResponse;
import com.example.sprintsight.dtos.responses.IssueTypeConfigurationResponse;
import com.example.sprintsight.entities.*;
import com.example.sprintsight.mappers.IssueConfigurationMapper;
import com.example.sprintsight.repositories.IssuePriorityConfigurationRepository;
import com.example.sprintsight.repositories.IssueRepository;
import com.example.sprintsight.repositories.IssueStatusConfigurationRepository;
import com.example.sprintsight.repositories.IssueTypeConfigurationRepository;
import jakarta.persistence.EntityNotFoundException;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.UUID;

@Slf4j
@Service
@RequiredArgsConstructor
public class IssueConfigurationService {
    private final IssueTypeConfigurationRepository typeRepository;
    private final IssuePriorityConfigurationRepository priorityRepository;
    private final IssueStatusConfigurationRepository statusRepository;
    private final IssueRepository issueRepository;
    private final ProjectService projectService;
    private final ProjectAuthorizationService authorizationService;
    private final IssueConfigurationMapper mapper;

    // ── Types ──────────────────────────────────────────────────────────────

    @Transactional(readOnly = true)
    public List<IssueTypeConfigurationResponse> getTypes(UUID projectId, UUID principalId) {
        authorizationService.getMemberOrThrow(principalId, projectId);

        return typeRepository.findByProject_Id(projectId).stream().map(mapper::toTypeResponse).toList();
    }

    @Transactional
    public IssueTypeConfigurationResponse createType(IssueTypeRequest request, UUID projectId, UUID principalId) {
        authorizationService.requireAnyRole(principalId, projectId,
                ProjectRole.PRODUCT_OWNER, ProjectRole.SCRUM_MASTER);

        if (typeRepository.existsByNameAndProject_Id(request.name(), projectId)) {
            throw new IllegalStateException("A type named '" + request.name() + "' already exists");
        }

        IssueTypeConfiguration Configuration = mapper.toTypeEntity(request);
        Configuration.setProject(projectService.findProject(projectId));

        if (request.isDefault()) {
            clearDefaultType(projectId);
        }

        return mapper.toTypeResponse(typeRepository.save(Configuration));
    }

    @Transactional
    public IssueTypeConfigurationResponse updateType(
            IssueTypeRequest request,
            UUID typeId,
            UUID projectId,
            UUID principalId
    ) {
        authorizationService.requireAnyRole(principalId, projectId,
                ProjectRole.PRODUCT_OWNER, ProjectRole.SCRUM_MASTER);

        IssueTypeConfiguration Configuration = findType(typeId, projectId);

        if (request.name() != null
                && typeRepository.existsByNameAndProject_Id(request.name(), projectId)
                && !Configuration.getName().equals(request.name())) {
            throw new IllegalStateException("A type named '" + request.name() + "' already exists");
        }

        if (request.isDefault()) {
            clearDefaultType(projectId);
        }

        mapper.updateTypeFromRequest(request, Configuration);
        return mapper.toTypeResponse(typeRepository.save(Configuration));
    }

    @Transactional
    public void deleteType(UUID typeId, UUID projectId, UUID principalId) {
        authorizationService.requireAnyRole(principalId, projectId,
                ProjectRole.PRODUCT_OWNER, ProjectRole.SCRUM_MASTER);

        IssueTypeConfiguration Configuration = findType(typeId, projectId);

        if (!typeRepository.existsByProject_IdAndIdNot(projectId, typeId)) {
            throw new IllegalStateException("Cannot delete the only issue type in this project");
        }

        if (issueRepository.existsByType_Id(typeId)) {
            throw new IllegalStateException("Cannot delete a type that is in use — reassign issues first");
        }

        typeRepository.delete(Configuration);
    }

    // ── Priorities ─────────────────────────────────────────────────────────

    @Transactional(readOnly = true)
    public List<IssuePriorityConfigurationResponse> getPriorities(UUID projectId, UUID principalId) {
        authorizationService.getMemberOrThrow(principalId, projectId);

        return priorityRepository.findByProject_IdOrderByOrderIndexAsc(projectId)
                .stream().map(mapper::toPriorityResponse).toList();
    }

    @Transactional
    public IssuePriorityConfigurationResponse createPriority(
            IssuePriorityRequest request,
            UUID projectId,
            UUID principalId
    ) {
        authorizationService.requireAnyRole(principalId, projectId,
                ProjectRole.PRODUCT_OWNER, ProjectRole.SCRUM_MASTER);

        if (priorityRepository.existsByNameAndProject_Id(request.name(), projectId)) {
            throw new IllegalStateException("A priority named '" + request.name() + "' already exists");
        }

        IssuePriorityConfiguration Configuration = mapper.toPriorityEntity(request);
        Configuration.setProject(projectService.findProject(projectId));

        if (request.isDefault()) {
            clearDefaultPriority(projectId);
        }

        return mapper.toPriorityResponse(priorityRepository.save(Configuration));
    }

    @Transactional
    public IssuePriorityConfigurationResponse updatePriority(
            IssuePriorityRequest request,
            UUID priorityId,
            UUID projectId,
            UUID principalId
    ) {
        authorizationService.requireAnyRole(principalId, projectId,
                ProjectRole.PRODUCT_OWNER, ProjectRole.SCRUM_MASTER);

        IssuePriorityConfiguration Configuration = findPriority(priorityId, projectId);

        if (request.name() != null
                && priorityRepository.existsByNameAndProject_Id(request.name(), projectId)
                && !Configuration.getName().equals(request.name())) {
            throw new IllegalStateException("A priority named '" + request.name() + "' already exists");
        }

        if (request.isDefault()) {
            clearDefaultPriority(projectId);
        }

        mapper.updatePriorityFromRequest(request, Configuration);
        return mapper.toPriorityResponse(priorityRepository.save(Configuration));
    }

    @Transactional
    public void deletePriority(UUID priorityId, UUID projectId, UUID principalId) {
        authorizationService.requireAnyRole(principalId, projectId,
                ProjectRole.PRODUCT_OWNER, ProjectRole.SCRUM_MASTER);

        IssuePriorityConfiguration Configuration = findPriority(priorityId, projectId);

        if (!priorityRepository.existsByProject_IdAndIdNot(projectId, priorityId)) {
            throw new IllegalStateException("Cannot delete the only priority in this project");
        }

        if (issueRepository.existsByPriority_Id(priorityId)) {
            throw new IllegalStateException("Cannot delete a priority that is in use — reassign issues first");
        }

        priorityRepository.delete(Configuration);
    }

    // ── Statuses ───────────────────────────────────────────────────────────

    @Transactional(readOnly = true)
    public List<IssueStatusConfigurationResponse> getStatuses(UUID projectId, UUID principalId) {
        authorizationService.getMemberOrThrow(principalId, projectId);

        return statusRepository.findByProject_IdOrderByOrderIndexAsc(projectId)
                .stream().map(mapper::toStatusResponse).toList();
    }

    @Transactional
    public IssueStatusConfigurationResponse createStatus(IssueStatusRequest request, UUID projectId, UUID principalId) {
        authorizationService.requireAnyRole(principalId, projectId,
                ProjectRole.PRODUCT_OWNER, ProjectRole.SCRUM_MASTER);

        if (statusRepository.existsByNameAndProject_Id(request.name(), projectId)) {
            throw new IllegalStateException("A status named '" + request.name() + "' already exists");
        }

        IssueStatusConfiguration Configuration = mapper.toStatusEntity(request);
        Configuration.setProject(projectService.findProject(projectId));

        if (request.isDefault()) {
            clearDefaultStatus(projectId);
        }

        return mapper.toStatusResponse(statusRepository.save(Configuration));
    }

    @Transactional
    public IssueStatusConfigurationResponse updateStatus(
            IssueStatusRequest request,
            UUID statusId,
            UUID projectId,
            UUID principalId
    ) {
        authorizationService.requireAnyRole(principalId, projectId,
                ProjectRole.PRODUCT_OWNER, ProjectRole.SCRUM_MASTER);

        IssueStatusConfiguration Configuration = findStatus(statusId, projectId);

        if (request.name() != null
                && statusRepository.existsByNameAndProject_Id(request.name(), projectId)
                && !Configuration.getName().equals(request.name())) {
            throw new IllegalStateException("A status named '" + request.name() + "' already exists");
        }

        if (!request.isCompleted() && Configuration.isCompleted()) {
            if (!statusRepository.existsByProject_IdAndIsCompletedTrue(projectId)) {
                throw new IllegalStateException(
                        "At least one status must be marked as completed for sprint closure to work");
            }
        }

        if (request.isDefault()) {
            clearDefaultStatus(projectId);
        }

        mapper.updateStatusFromRequest(request, Configuration);
        return mapper.toStatusResponse(statusRepository.save(Configuration));
    }

    @Transactional
    public void deleteStatus(UUID statusId, UUID projectId, UUID principalId) {
        authorizationService.requireAnyRole(principalId, projectId,
                ProjectRole.PRODUCT_OWNER, ProjectRole.SCRUM_MASTER);

        IssueStatusConfiguration Configuration = findStatus(statusId, projectId);

        if (!statusRepository.existsByProject_IdAndIdNot(projectId, statusId)) {
            throw new IllegalStateException("Cannot delete the only status in this project");
        }

        if (Configuration.isCompleted()
                && !statusRepository.existsByProject_IdAndIsCompletedTrue(projectId)) {
            throw new IllegalStateException(
                    "Cannot delete the last completed status — sprint closure requires at least one");
        }

        if (issueRepository.existsByStatus_Id(statusId)) {
            throw new IllegalStateException(
                    "Cannot delete a status that is in use — move issues to another status first");
        }

        statusRepository.delete(Configuration);
    }

    // ── Default resolution (used by IssueService) ─────────────────────────

    public IssueTypeConfiguration getDefaultType(UUID projectId) {
        return typeRepository.findByProject_IdAndIsDefaultTrue(projectId)
                .orElseThrow(() -> new IllegalStateException(
                        "No default issue type Configured for this project"));
    }

    public IssuePriorityConfiguration getDefaultPriority(UUID projectId) {
        return priorityRepository.findByProject_IdAndIsDefaultTrue(projectId)
                .orElseThrow(() -> new IllegalStateException(
                        "No default priority Configured for this project"));
    }

    public IssueStatusConfiguration getDefaultStatus(UUID projectId) {
        return statusRepository.findByProject_IdAndIsDefaultTrue(projectId)
                .orElseThrow(() -> new IllegalStateException(
                        "No default status Configured for this project"));
    }

    public IssueTypeConfiguration findType(UUID typeId, UUID projectId) {
        IssueTypeConfiguration Configuration = typeRepository.findById(typeId)
                .orElseThrow(() -> new EntityNotFoundException("Issue type not found"));

        if (!Configuration.getProject().getId().equals(projectId)) {
            throw new AccessDeniedException("Issue type does not belong to this project");
        }

        return Configuration;
    }

    public IssuePriorityConfiguration findPriority(UUID priorityId, UUID projectId) {
        IssuePriorityConfiguration Configuration = priorityRepository.findById(priorityId)
                .orElseThrow(() -> new EntityNotFoundException("Priority not found"));

        if (!Configuration.getProject().getId().equals(projectId)) {
            throw new AccessDeniedException("Priority does not belong to this project");
        }

        return Configuration;
    }

    public IssueStatusConfiguration findStatus(UUID statusId, UUID projectId) {
        IssueStatusConfiguration Configuration = statusRepository.findById(statusId)
                .orElseThrow(() -> new EntityNotFoundException("Status not found"));

        if (!Configuration.getProject().getId().equals(projectId)) {
            throw new AccessDeniedException("Status does not belong to this project");
        }

        return Configuration;
    }

    // ── Default seeding (called by ProjectService on project creation) ─────

    public void seedDefaults(Project project) {
        List<IssueTypeConfiguration> types = List.of(
                buildType(project, "Bug",   true),
                buildType(project, "Task",  false),
                buildType(project, "Story", false)
        );
        typeRepository.saveAll(types);

        List<IssuePriorityConfiguration> priorities = List.of(
                buildPriority(project, "Critical", 0, false),
                buildPriority(project, "High",     1, false),
                buildPriority(project, "Medium",   2, true),
                buildPriority(project, "Low",      3, false)
        );
        priorityRepository.saveAll(priorities);

        List<IssueStatusConfiguration> statuses = List.of(
                buildStatus(project, "To Do",       0, false, true),
                buildStatus(project, "In Progress", 1, false, false),
                buildStatus(project, "Done",        2, true,  false)
        );
        statusRepository.saveAll(statuses);
    }

    private void clearDefaultType(UUID projectId) {
        typeRepository.findByProject_IdAndIsDefaultTrue(projectId)
                .ifPresent(c -> { c.setDefault(false); typeRepository.save(c); });
    }

    private void clearDefaultPriority(UUID projectId) {
        priorityRepository.findByProject_IdAndIsDefaultTrue(projectId)
                .ifPresent(c -> { c.setDefault(false); priorityRepository.save(c); });
    }

    private void clearDefaultStatus(UUID projectId) {
        statusRepository.findByProject_IdAndIsDefaultTrue(projectId)
                .ifPresent(c -> { c.setDefault(false); statusRepository.save(c); });
    }

    private IssueTypeConfiguration buildType(Project p, String name, boolean isDefault) {
        IssueTypeConfiguration c = new IssueTypeConfiguration();
        c.setProject(p);
        c.setName(name);
        c.setDefault(isDefault);

        return c;
    }

    private IssuePriorityConfiguration buildPriority(Project p, String name, int order, boolean isDefault) {
        IssuePriorityConfiguration c = new IssuePriorityConfiguration();
        c.setProject(p);
        c.setName(name);
        c.setOrderIndex(order);
        c.setDefault(isDefault);

        return c;
    }

    private IssueStatusConfiguration buildStatus(
            Project p,
            String name,
            int order,
            boolean isCompleted,
            boolean isDefault
    ) {
        IssueStatusConfiguration c = new IssueStatusConfiguration();
        c.setProject(p);
        c.setName(name);
        c.setOrderIndex(order);
        c.setCompleted(isCompleted);
        c.setDefault(isDefault);

        return c;
    }
}

package com.example.sprintsight.services;

import com.example.sprintsight.dtos.requests.IssueRequest;
import com.example.sprintsight.dtos.responses.IssueResponse;
import com.example.sprintsight.dtos.responses.IssueSummaryResponse;
import com.example.sprintsight.entities.*;
import com.example.sprintsight.mappers.IssueMapper;
import com.example.sprintsight.repositories.*;
import jakarta.persistence.EntityNotFoundException;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class IssueService {
    private final SprintRepository sprintRepository;
    private final SprintIssueRepository sprintIssueRepository;
    private final IssueRepository issueRepository;
    private final IssueEventRepository issueEventRepository;
    private final ComponentRepository componentRepository;
    private final UserService userService;
    private final ProjectService projectService;
    private final ProjectAuthorizationService authorizationService;
    private final IssueConfigurationService issueConfigurationService;
    private final IssueMapper issueMapper;

    @Transactional(readOnly = true)
    public IssueResponse getIssue(UUID issueId, UUID principalId) {
        Issue issue = findIssue(issueId);

        authorizationService.getMemberOrThrow(principalId, issue.getProject().getId());

        return issueMapper.toIssueResponse(issue);
    }

    @Transactional(readOnly = true)
    public List<IssueSummaryResponse> getBacklog(UUID projectId, UUID principalId) {
        authorizationService.getMemberOrThrow(principalId, projectId);

        List<UUID> activeSprintIssueIds = sprintRepository
                .findByProject_IdAndStatus(projectId, SprintStatus.ACTIVE)
                .stream()
                .flatMap(s -> sprintIssueRepository
                        .findBySprint_IdAndRemovedAtIsNull(s.getId()).stream())
                .map(si -> si.getIssue().getId())
                .toList();

        return issueRepository.findByProject_Id(projectId)
                .stream()
                .filter(i -> !activeSprintIssueIds.contains(i.getId()))
                .map(issueMapper::toIssueSummaryResponse)
                .toList();
    }

    @Transactional(readOnly = true)
    public List<IssueSummaryResponse> getProjectIssues(UUID projectId, UUID principalId) {
        authorizationService.getMemberOrThrow(principalId, projectId);

        return issueRepository.findByProject_Id(projectId)
                .stream()
                .map(issueMapper::toIssueSummaryResponse)
                .toList();
    }

    @Transactional
    public IssueResponse createIssue(
            IssueRequest request,
            UUID projectId,
            UUID principalId
    ) {
        authorizationService.requireAnyRole(principalId, projectId, ProjectRole.PRODUCT_OWNER,
                ProjectRole.SCRUM_MASTER, ProjectRole.DEVELOPER);

        Project project = projectService.findProject(projectId);
        User creator = userService.findUser(principalId);

        Issue issue = issueMapper.toEntity(request);
        issue.setProject(project);
        issue.setCreatedBy(creator);

        issue.setType(issueConfigurationService.findType(request.typeId(), projectId));
        issue.setPriority(issueConfigurationService.findPriority(request.priorityId(), projectId));
        issue.setStatus(issueConfigurationService.getDefaultStatus(projectId));

        if (request.assignedTo() != null) {
            authorizationService.requireAnyRole(principalId, projectId, ProjectRole.PRODUCT_OWNER,
                    ProjectRole.SCRUM_MASTER);

            issue.setAssignedTo(userService.findUser(request.assignedTo()));
        }

        if (request.componentIds() != null && !request.componentIds().isEmpty()) {
            issue.setComponents(resolveComponents(request.componentIds(), projectId));
        }

        Issue saved = issueRepository.save(issue);

        log.info("Created issue {} in project {}", saved.getId(), projectId);

        return issueMapper.toIssueResponse(saved);
    }

    @Transactional
    public IssueResponse updateIssue(
            IssueRequest request,
            UUID issueId,
            UUID principalId
    ) {
        Issue issue = findIssue(issueId);
        UUID projectId = issue.getProject().getId();

        ProjectRole role = authorizationService.getRoleOrThrow(principalId, projectId);

        boolean isPrivileged = role == ProjectRole.PRODUCT_OWNER || role == ProjectRole.SCRUM_MASTER;
        boolean isCreator = issue.getCreatedBy().getId().equals(principalId);

        if (!isPrivileged && !isCreator) {
            throw new AccessDeniedException("You can only edit issues you created");
        }

        recordChanges(issue, request, principalId);
        issueMapper.updateIssueFromRequest(request, issue);

        if (request.typeId() != null) {
            issue.setType(issueConfigurationService.findType(request.typeId(), projectId));
        }

        if (request.priorityId() != null) {
            if (!isPrivileged) {
                throw new AccessDeniedException("Only product owners and scrum masters can change priority");
            }

            issue.setPriority(issueConfigurationService.findPriority(request.priorityId(), projectId));
        }

        if (request.statusId() != null) {
            issue.setStatus(issueConfigurationService.findStatus(request.statusId(), projectId));
        }

        if (request.assignedTo() != null) {
            if (!isPrivileged) {
                throw new AccessDeniedException("Only product owners and scrum masters can assign issues");
            }

            issue.setAssignedTo(userService.findUser(request.assignedTo()));
        }

        if (request.componentIds() != null) {
            issue.setComponents(resolveComponents(request.componentIds(), projectId));
        }

        Issue saved = issueRepository.save(issue);

        log.info("Updated issue {}", issueId);

        return issueMapper.toIssueResponse(saved);
    }

    @Transactional
    public void deleteIssue(UUID issueId, UUID principalId) {
        Issue issue = findIssue(issueId);

        authorizationService.requireAnyRole(principalId, issue.getProject().getId(), ProjectRole.PRODUCT_OWNER,
                ProjectRole.SCRUM_MASTER);

        issueRepository.delete(issue);

        log.info("Deleted issue {}", issueId);
    }

    public Issue findIssue(UUID issueId) {
        return issueRepository.findById(issueId).orElseThrow(() -> new EntityNotFoundException("Issue not found"));
    }

    private Set<Component> resolveComponents(Set<UUID> componentIds, UUID projectId) {
        return componentIds.stream()
                .map(componentId -> componentRepository.findById(componentId)
                        .filter(c -> c.getProject().getId().equals(projectId))
                        .orElseThrow(() -> new EntityNotFoundException(
                                "Component " + componentId + " not found in this project")))
                .collect(Collectors.toSet());
    }

    private void recordChanges(Issue issue, IssueRequest request, UUID principalId) {
        User changer = userService.findUser(principalId);
        List<IssueEvent> events = new ArrayList<>();

        if (!request.title().equals(issue.getTitle())) {
            events.add(buildEvent(issue, changer, "title", issue.getTitle(), request.title()));
        }

        if (!request.description().equals(issue.getDescription())) {
            events.add(buildEvent(issue, changer, "description", issue.getDescription(), request.description()));
        }

        if (request.type() != issue.getType()) {
            events.add(buildEvent(issue, changer, "type", issue.getType().name(), request.type().name()));
        }

        if (request.priority() != issue.getPriority()) {
            events.add(buildEvent(issue, changer, "priority", issue.getPriority().name(),
                    request.priority().name()));
        }

        if (request.status() != issue.getStatus()) {
            events.add(buildEvent(issue, changer, "status", issue.getStatus().name(), request.status().name()));
        }

        if (!Objects.equals(request.storyPoints(), issue.getStoryPoints())) {
            events.add(buildEvent(issue, changer, "storyPoints", issue.getStoryPoints().toString(),
                    request.storyPoints().toString()));
        }

        if (!request.fixVersion().equals(issue.getFixVersion())) {
            events.add(buildEvent(issue, changer, "fixVersion", issue.getFixVersion(), request.fixVersion()));
        }

        UUID current = issue.getAssignedTo() != null ? issue.getAssignedTo().getId() : null;
        UUID updated = request.assignedTo();

        if (!Objects.equals(current, updated)) {
            events.add(buildEvent(issue, changer, "assignedTo", current != null ? current.toString() : "null",
                    updated != null ? updated.toString() : "null"));
        }

        if (!events.isEmpty()) {
            issueEventRepository.saveAll(events);
        }
    }

    private IssueEvent buildEvent(Issue issue, User changer, String field, String oldVal, String newVal) {
        IssueEvent event = new IssueEvent();
        event.setIssue(issue);
        event.setChangedBy(changer);
        event.setFieldName(field);
        event.setOldValue(oldVal);
        event.setNewValue(newVal);

        return event;
    }
}

package com.example.sprintsight.services;

import com.example.sprintsight.entities.ProjectMember;
import com.example.sprintsight.entities.ProjectMemberId;
import com.example.sprintsight.entities.ProjectRole;
import com.example.sprintsight.repositories.ProjectMemberRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.security.access.AccessDeniedException;
import org.springframework.stereotype.Service;

import java.util.Arrays;
import java.util.UUID;

@Service
@RequiredArgsConstructor
public class ProjectAuthorizationService {
    private final ProjectMemberRepository projectMemberRepository;

    public ProjectMember getMemberOrThrow(UUID userId, UUID projectId) {
        return projectMemberRepository.findById(new ProjectMemberId(projectId, userId))
                .orElseThrow(() -> new AccessDeniedException("You are not a member of this project"));
    }

    public void requireAnyRole(UUID userId, UUID projectId, ProjectRole... roles) {
        ProjectMember member = getMemberOrThrow(userId, projectId);

        if (Arrays.stream(roles).noneMatch(r -> r == member.getProjectRole())) {
            throw new AccessDeniedException("Insufficient permissions for this action");
        }
    }

    public boolean hasAnyRole(UUID userId, UUID projectId, ProjectRole... roles) {
        return projectMemberRepository.findById(new ProjectMemberId(projectId, userId))
                .map(m -> Arrays.stream(roles).anyMatch(r -> r == m.getProjectRole()))
                .orElse(false);
    }

    public ProjectRole getRoleOrThrow(UUID userId, UUID projectId) {
        return getMemberOrThrow(userId, projectId).getProjectRole();
    }
}

package com.example.sprintsight.services;

